function ChatApp() {
  const [messages, setMessages] = useState([]);

  const sendMessage = async (text, recipient) => {
    const encrypted = await encrypt({
      text,
      pubKey: await getPublicKey(recipient)
    });

    socket.emit('message', {
      to: recipient,
      ciphertext: encrypted
    });
  };

  socket.on('message', async msg => {
    const decrypted = await decrypt(msg.ciphertext);
    setMessages([...messages, decrypted]);
  });
}
